def topo_sort(edges):
    """Topological sort of a directed graph.
    edges: list of (from_node, to_node) tuples
    Returns a list of nodes in topological order.
    Raises ValueError if the graph contains a cycle.
    """
    if not edges:
        # Handle empty edges list: return empty list (no nodes to sort)
        return []

    # Build adjacency list and in-degree count
    graph = {}
    in_degree = {}
    all_nodes = set()

    # Collect all nodes
    for src, dst in edges:
        all_nodes.add(src)
        all_nodes.add(dst)
        if src not in graph:
            graph[src] = set()  # Use set to avoid duplicate edges
        graph[src].add(dst)

        # Initialize in_degree for both nodes
        if src not in in_degree:
            in_degree[src] = 0
        if dst not in in_degree:
            in_degree[dst] = 0

    # Calculate in-degrees from unique edges only
    for src in graph:
        for dst in graph[src]:
            in_degree[dst] += 1

    # Kahn's algorithm
    queue = [node for node in all_nodes if in_degree[node] == 0]
    result = []

    while queue:
        node = queue.pop(0)
        result.append(node)
        if node in graph:
            for neighbor in graph[node]:
                in_degree[neighbor] -= 1
                if in_degree[neighbor] == 0:
                    queue.append(neighbor)

    # Check if all nodes were processed
    if len(result) != len(all_nodes):
        raise ValueError('Graph contains a cycle')

    return result
